/// Maps Frank routes to RDF resource identities.
module RouteMapper =

    type MappedResource = {
        ResourceUri: Uri
        RouteTemplate: string
        UriTemplate: string
        Name: string option
        LinkedClass: Uri option
    }

    let private routeToSlug (route: string) =
        route.TrimStart('/').Replace("/", "_").Replace("{", "").Replace("}", "")

    let private resourceUri (config: TypeMapper.MappingConfig) (route: string) =
        let base' = config.BaseUri.ToString().TrimEnd('/')
        let cleanRoute = route.TrimStart('/')
        Uri(base' + "/resources/" + cleanRoute)

    let private uriTemplate (config: TypeMapper.MappingConfig) (route: string) =
        let base' = config.BaseUri.ToString().TrimEnd('/')
        let cleanRoute = route.TrimStart('/')
        base' + "/resources/" + cleanRoute

    let private findLinkedClass (config: TypeMapper.MappingConfig) (resource: AnalyzedResource) (types: AnalyzedType list) : Uri option =
        if not resource.HasLinkedData then None
        else
            // Try to match resource name or route segment to a type
            let candidateName =
                resource.Name
                |> Option.defaultWith (fun () ->
                    let parts = resource.RouteTemplate.TrimStart('/').Split('/')
                    parts |> Array.tryHead |> Option.defaultValue "")
            types
            |> List.tryFind (fun t ->
                t.ShortName.ToLowerInvariant() = candidateName.ToLowerInvariant()
                || t.ShortName.ToLowerInvariant() + "s" = candidateName.ToLowerInvariant())
            |> Option.map (fun t ->
                Uri(config.BaseUri.ToString().TrimEnd('/') + "/types/" + t.ShortName))

    let mapRoutes (config: TypeMapper.MappingConfig) (resources: AnalyzedResource list) (types: AnalyzedType list) : IGraph =
        let graph = createGraph ()
        let rdfType = createUriNode graph (Uri Rdf.Type)

        for res in resources do
            let resUri = resourceUri config res.RouteTemplate
            let resNode = createUriNode graph resUri
            let template = uriTemplate config res.RouteTemplate

            // rdf:type hydra:Resource
            assertTriple graph (resNode, rdfType, createUriNode graph (Uri Hydra.Resource))

            // rdfs:label
            let label = res.Name |> Option.defaultValue res.RouteTemplate
            assertTriple graph (resNode, createUriNode graph (Uri Rdfs.Label), createLiteralNode graph label None)

            // hydra:template
            assertTriple graph (
                resNode,
                createUriNode graph (Uri Hydra.Template),
                createLiteralNode graph template (Some(Uri Xsd.String)))

            // hydra:supportedClass if linked
            let linkedClass = findLinkedClass config res types
            linkedClass |> Option.iter (fun classUri ->
                assertTriple graph (resNode, createUriNode graph (Uri Hydra.SupportedClass), createUriNode graph classUri))

        graph

namespace Frank.LinkedData.Rdf

open System
open System.Collections
open System.Collections.Concurrent
open System.Collections.Generic
open System.Reflection
open Microsoft.FSharp.Reflection
open VDS.RDF

/// Projects handler return values to RDF triples.
module InstanceProjector =

    /// Cache: Type -> PropertyInfo[]
    let private propertyCache = ConcurrentDictionary<Type, PropertyInfo[]>()

    /// Cache: ontology graph identity hash -> (lowercase local name -> INode)
    let private ontologyIndexCache = ConcurrentDictionary<int, Dictionary<string, INode>>()

    let private getProperties (t: Type) =
        propertyCache.GetOrAdd(t, fun t -> t.GetProperties(BindingFlags.Public ||| BindingFlags.Instance))

    let private getOntologyIndex (ontologyGraph: IGraph) =
        let key = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode(ontologyGraph)
        ontologyIndexCache.GetOrAdd(key, fun _ ->
            let dict = Dictionary<string, INode>(StringComparer.OrdinalIgnoreCase)
            for triple in ontologyGraph.Triples do
                match triple.Subject with
                | :? IUriNode as uriNode ->
                    let uri = uriNode.Uri.ToString()
                    // Extract local name (after last / or #)
                    let lastSlash = uri.LastIndexOf('/')
                    let lastHash = uri.LastIndexOf('#')
                    let idx = max lastSlash lastHash
                    if idx >= 0 && idx < uri.Length - 1 then
                        let localName = uri.Substring(idx + 1)
                        if not (dict.ContainsKey(localName)) then
                            dict.[localName] <- triple.Subject
                | _ -> ()
            dict
        )

    let private xsd prefix = UriFactory.Root.Create(sprintf "http://www.w3.org/2001/XMLSchema#%s" prefix)

    let rec private addTriples
        (ontologyGraph: IGraph)
        (output: IGraph)
        (subject: INode)
        (instance: obj)
        (instanceType: Type) =

        let index = getOntologyIndex ontologyGraph
        let props = getProperties instanceType

        for prop in props do
            let propName = prop.Name
            match index.TryGetValue(propName) with
            | false, _ -> () // No matching ontology property, skip
            | true, ontNode ->
                let predicateUri =
                    match ontNode with
                    | :? IUriNode as u -> u.Uri
                    | _ -> Uri(sprintf "urn:unknown:%s" propName)
                let predicate = output.CreateUriNode(UriFactory.Root.Create(predicateUri.ToString()))
                let value = prop.GetValue(instance)
                if not (isNull value) then
                    projectValue ontologyGraph output subject predicate value (prop.PropertyType)

    and private projectValue
        (ontologyGraph: IGraph)
        (output: IGraph)
        (subject: INode)
        (predicate: INode)
        (value: obj)
        (valueType: Type) =

        // Handle FSharpOption
        if valueType.IsGenericType && valueType.GetGenericTypeDefinition() = typedefof<option<_>> then
            let cases = FSharpType.GetUnionCases(valueType)
            let tag = FSharpValue.PreComputeUnionTagReader(valueType)
            let tagVal = tag value
            // None case is tag 0, Some is tag 1
            if tagVal = 1 then // Some
                let someCase = cases |> Array.find (fun c -> c.Tag = 1)
                let fields = someCase.GetFields()
                if fields.Length > 0 then
                    let innerValue = (FSharpValue.GetUnionFields(value, valueType) |> snd).[0]
                    if not (isNull innerValue) then
                        projectValue ontologyGraph output subject predicate innerValue (fields.[0].PropertyType)
            // else None: skip
        // Handle string (before IEnumerable check)
        elif valueType = typeof<string> then
            let literal = output.CreateLiteralNode(value :?> string)
            output.Assert(Triple(subject, predicate, literal)) |> ignore
        // Handle IEnumerable (collections)
        elif typeof<IEnumerable>.IsAssignableFrom(valueType) && valueType <> typeof<string> then
            let enumerable = value :?> IEnumerable
            for item in enumerable do
                if not (isNull item) then
                    projectValue ontologyGraph output subject predicate item (item.GetType())
        // Handle nested F# records
        elif FSharpType.IsRecord(valueType) then
            let blank = output.CreateBlankNode()
            output.Assert(Triple(subject, predicate, blank)) |> ignore
            addTriples ontologyGraph output blank value valueType
        else
            let objectNode =
                match value with
                | :? int as i ->
                    output.CreateLiteralNode(i.ToString(), xsd "integer")
                | :? int64 as i ->
                    output.CreateLiteralNode(i.ToString(), xsd "integer")
                | :? float as f ->
                    output.CreateLiteralNode(f.ToString("R"), xsd "double")
                | :? decimal as d ->
                    output.CreateLiteralNode(d.ToString(), xsd "decimal")
                | :? bool as b ->
                    output.CreateLiteralNode((if b then "true" else "false"), xsd "boolean")
                | :? DateTimeOffset as dto ->
                    output.CreateLiteralNode(dto.ToString("o"), xsd "dateTime")
                | :? DateTime as dt ->
                    output.CreateLiteralNode(dt.ToString("o"), xsd "dateTime")
                | _ ->
                    output.CreateLiteralNode(value.ToString())
            output.Assert(Triple(subject, predicate, objectNode)) |> ignore

    /// Projects an object instance to RDF triples using ontology property mappings.
    let project (ontologyGraph: IGraph) (resourceUri: Uri) (instance: obj) : IGraph =
        let output = new Graph()
        let subject = output.CreateUriNode(UriFactory.Root.Create(resourceUri.ToString()))
        let instanceType = instance.GetType()
        addTriples ontologyGraph output subject instance instanceType
        output

namespace Frank.LinkedData.Rdf

open System
open System.IO
open System.Reflection
open System.Text.Json
open VDS.RDF
open VDS.RDF.Parsing

/// Manifest describing the semantic resources embedded in an assembly.
type SemanticManifest =
    { Version      : string
      BaseUri      : string
      SourceHash   : string
      Vocabularies : string list
      GeneratedAt  : DateTimeOffset }

/// The loaded ontology, shapes, and manifest from an assembly's embedded resources.
type LoadedSemantics =
    { OntologyGraph : IGraph
      ShapesGraph   : IGraph
      Manifest      : SemanticManifest }

/// Loads ontology and SHACL shapes from embedded resources.
module GraphLoader =

    let private manifestResource = "Frank.Semantic.manifest.json"
    let private ontologyResource = "Frank.Semantic.ontology.owl.xml"
    let private shapesResource   = "Frank.Semantic.shapes.shacl.ttl"

    let private missingResourceError (assembly: Assembly) (resource: string) =
        let msg =
            sprintf
                "Assembly '%s' does not contain embedded resource '%s'. Run 'frank-cli compile' and add the output files as EmbeddedResource items."
                (assembly.GetName().Name)
                resource
        Error msg

    let private loadStream (assembly: Assembly) resource =
        match assembly.GetManifestResourceStream(resource) with
        | null -> missingResourceError assembly resource
        | s    -> Ok s

    let load (assembly: Assembly) : Result<LoadedSemantics, string> =
        try
            // 1. Load and deserialize manifest
            match loadStream assembly manifestResource with
            | Error e -> Error e
            | Ok manifestStream ->
            use _ms = manifestStream
            let options = JsonSerializerOptions(PropertyNameCaseInsensitive = true)
            let manifest = JsonSerializer.Deserialize<SemanticManifest>(manifestStream, options)

            // 2. Load ontology (RDF/XML)
            match loadStream assembly ontologyResource with
            | Error e -> Error e
            | Ok ontologyStream ->
            use _os = ontologyStream
            let ontologyGraph = new Graph()
            let rdfXmlParser = RdfXmlParser()
            rdfXmlParser.Load(ontologyGraph, new StreamReader(ontologyStream))

            // 3. Load shapes (Turtle)
            match loadStream assembly shapesResource with
            | Error e -> Error e
            | Ok shapesStream ->
            use _ss = shapesStream
            let shapesGraph = new Graph()
            let turtleParser = TurtleParser()
            turtleParser.Load(shapesGraph, new StreamReader(shapesStream))

            Ok { OntologyGraph = ontologyGraph
                 ShapesGraph   = shapesGraph
                 Manifest      = manifest }
        with
        | :? RdfParseException as ex ->
            Error (sprintf "RDF parse error: %s" ex.Message)
